 33→type Props = NativeStackScreenProps<RootStackParamList, 'PostDetail'>;
 34→
 35→const toCount = (value: unknown): number | null => {
 36→  const parsed = Number(value);
 37→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : null;
 38→};
 39→
 40→const resolveCount = (
 41→  aggregate: Array<{count?: number}> | undefined,
 42→  fallback?: number,
 43→): number => {
 44→  return toCount(aggregate?.[0]?.count) ?? toCount(fallback) ?? 0;
 45→};
 46→
 47→const formatRelativeDate = (value: string | undefined): string => {
 48→  if (!value) return '';
 49→  const date = new Date(value);
 50→  if (Number.isNaN(date.getTime())) return value;
 51→  const now = Date.now();
 52→  const diff = now - date.getTime();
 53→  const mins = Math.floor(diff / 60000);
 54→  if (mins < 1) return 'Just now';
 55→  if (mins < 60) return `${mins}m ago`;
 56→  const hours = Math.floor(mins / 60);
 57→  if (hours < 24) return `${hours}h ago`;
 58→  const days = Math.floor(hours / 24);
 59→  if (days < 7) return `${days}d ago`;
 60→  return date.toLocaleDateString(undefined, {month: 'short', day: 'numeric', year: 'numeric'});
 61→};
 62→
 63→const extractBannerImage = (content: string | null | undefined): string | null => {
 64→  if (!content) return null;
 65→  try {
 66→    const parsed = JSON.parse(content);
 67→    const findImage = (node: any): string | null => {
 68→      if (node.type === 'image' && node.src) return node.src;
 69→      if (node.children) {
 70→        for (const child of node.children) {
 71→          const found = findImage(child);
 72→          if (found) return found;
 73→        }
 74→      }
 75→      return null;
 76→    };
 77→    return findImage(parsed.root ?? parsed);
 78→  } catch {
 79→    return null;
 80→  }
 81→};
 82→
 83→type CommentThreadProps = {
 84→  comment: JournalComment;
 85→  postId: string;
 86→  allComments: JournalComment[];
 87→  fetchedReplies: Record<string, JournalComment[]>;
 88→  loadingReplies: Set<string>;
 89→  isLoggedIn: boolean;
 90→  onReply: (commentId: string, userName: string) => void;
 91→  onToggleReplies: (commentId: string) => void;
 92→  expandedReplies: Set<string>;
 93→  colors: Palette;
 94→  depth: number;
 95→};
 96→
 97→function CommentThread({
 98→  comment,
 99→  postId,
100→  allComments,
101→  fetchedReplies,
102→  loadingReplies,
103→  isLoggedIn,
104→  onReply,
105→  onToggleReplies,
106→  expandedReplies,
107→  colors,
108→  depth,
109→}: CommentThreadProps) {
110→  const isExpanded = expandedReplies.has(comment.id);
111→  const fetched = fetchedReplies[comment.id];
112→  const localReplies = allComments.filter(c => c.parent_id === comment.id);
113→  const replies = fetched ?? localReplies;
114→  const replyCount = comment.reply_count ?? replies.length;
115→  const isLoadingReplies = loadingReplies.has(comment.id);
116→  const userName = comment.users?.name || 'User';
117→
118→  const avatarSize = depth === 0 ? 28 : 24;
119→  const bodyPaddingLeft = depth === 0 ? 36 : 32;
120→  const repliesMarginLeft = depth === 0 ? 36 : 24;
121→
122→  return (
123→    <View>
124→      <View style={[styles.commentCard, {borderTopColor: colors.borderCard}]}>
125→        <View style={styles.commentHeader}>
126→          <Avatar
127→            uri={(comment.users as any)?.image_url}
128→            name={comment.users?.name}
129→            size={avatarSize}
130→          />
131→          <View style={styles.commentMeta}>
132→            <Text style={[styles.commentAuthor, {color: colors.textPrimary}]}>
133→              {userName}
134→            </Text>
135→            <Text style={[styles.commentTime, {color: colors.textFaint}]}>
136→              {formatRelativeDate(comment.created_at)}
137→            </Text>
138→          </View>
139→        </View>
140→        <Text style={[styles.commentBody, {color: colors.textSecondary, paddingLeft: bodyPaddingLeft}]}>
141→          {comment.comment || ''}
142→        </Text>
143→        <View style={[styles.commentActions, {paddingLeft: bodyPaddingLeft}]}>
144→          {isLoggedIn && (
145→            <Pressable
146→              style={styles.actionButton}
147→              onPress={() => onReply(comment.id, userName)}>
148→              <ReplyIcon size={14} color={colors.textMuted} />
149→              <Text style={[styles.actionText, {color: colors.textMuted}]}>
150→                Reply
151→              </Text>
152→            </Pressable>
153→          )}
154→          {replyCount > 0 && (
155→            <Pressable
156→              style={styles.actionButton}
157→              onPress={() => onToggleReplies(comment.id)}>
158→              <Text style={[styles.actionText, {color: colors.accentGold}]}>
159→                {isExpanded ? 'Hide replies' : `Show ${replyCount} ${replyCount === 1 ? 'reply' : 'replies'}`}
160→              </Text>
161→            </Pressable>
162→          )}
163→        </View>
164→      </View>
165→
166→      {isExpanded && (
167→        <View style={[styles.repliesContainer, {borderLeftColor: colors.borderLight, marginLeft: repliesMarginLeft}]}>
168→          {isLoadingReplies ? (
169→            <View style={styles.commentLoading}>
170→              <ActivityIndicator size="small" color={colors.loaderColor} />
171→            </View>
172→          ) : (
173→            replies.map(reply => (
174→              <CommentThread
175→                key={reply.id}
176→                comment={reply}
177→                postId={postId}
178→                allComments={allComments}
179→                fetchedReplies={fetchedReplies}
180→                loadingReplies={loadingReplies}
181→                isLoggedIn={isLoggedIn}
182→                onReply={onReply}
183→                onToggleReplies={onToggleReplies}
184→                expandedReplies={expandedReplies}
185→                colors={colors}
186→                depth={depth + 1}
187→              />
188→            ))
189→          )}
190→        </View>
191→      )}
192→    </View>
193→  );
194→}
