    gap: spacing.md,
    marginBottom: spacing.md,
  },
  authorInfo: {
    flex: 1,
  },
  authorNameRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 4,
  },
  authorName: {
    fontFamily: fonts.ui.semiBold,
    fontSize: 15,
  },
  dateText: {
    fontFamily: fonts.ui.regular,
    fontSize: 13,
    marginTop: 2,
  },
  divider: {
    height: 1,
    marginVertical: spacing.xl,
  },
  sectionTitle: {
    ...typeScale.h3,
    marginBottom: spacing.md,
  },
  errorText: {
    fontFamily: fonts.ui.medium,
    fontSize: 15,
    textAlign: 'center',
    marginTop: spacing.xxxl,
  },
  repostSection: {
    borderRadius: radii.xl,
    borderWidth: 1,
    padding: spacing.md,
    gap: spacing.md,
    marginTop: spacing.sm,
  },
  noComments: {
