 31→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 32→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 33→  const {user, session} = useAuth();
 34→  const token = session?.access_token ?? '';
 35→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 36→
 37→  const query = useInfiniteQuery({
 38→    queryKey: ['profileWritings', userId],
 39→    queryFn: ({pageParam}) =>
 40→      mobileApi.getUserJournals(token, userId, pageParam ?? null, PAGE_SIZE),
 41→    initialPageParam: null as string | null,
 42→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 43→  });
 44→
 45→  const queryKey = ['profileWritings', userId];
 46→
 47→  const reactionMutation = useMutation<
 48→    {message?: string},
 49→    Error,
 50→    {journalId: string; receiverId: string; reactionType: string},
 51→    {prev?: {pages: CursorPage<JournalItem>[]}}
 52→  >({
 53→    mutationFn: async ({journalId, receiverId, reactionType}) => {
 54→      if (!token) throw new Error('Please log in to react.');
 55→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 56→    },
 57→    onMutate: async ({journalId, reactionType}) => {
 58→      await queryClient.cancelQueries({queryKey});
 59→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey);
 60→      if (prev) {
 61→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey, old => {
 62→          if (!old) return old;
 63→          return {
 64→            ...old,
 65→            pages: old.pages.map(page => ({
 66→              ...page,
 67→              data: page.data.map(item => {
 68→                if (item.id !== journalId) return item;
 69→                const removing = item.user_reaction === reactionType;
 70→                const currentCount =
 71→                  (item.reaction_count?.[0]?.count ??
 72→                    item.like_count?.[0]?.count ??
 73→                    item.likes_count ??
 74→                    0) as number;
 75→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
 76→                return {
 77→                  ...item,
 78→                  user_reaction: removing ? null : reactionType,
 79→                  has_liked: removing ? false : true,
 80→                  like_count: [{count: Math.max(0, currentCount + delta)}],
 81→                };
 82→              }),
 83→            })),
 84→          };
 85→        });
 86→      }
 87→      return {prev};
 88→    },
 89→    onError: (_err, _vars, context) => {
 90→      if (context?.prev) {
 91→        queryClient.setQueryData(queryKey, context.prev);
 92→      }
 93→    },
 94→    onSettled: () => {
 95→      queryClient.invalidateQueries({queryKey});
 96→    },
 97→  });
 98→
 99→  const bookmarkMutation = useBookmarkMutation(token, queryKey);
100→  const repostMutation = useRepostMutation(token);
101→
102→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
103→    if (!token) return;
104→    reactionMutation.mutate({journalId, receiverId, reactionType});
105→  };
106→
107→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
108→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
109→  };
110→
111→  const handleBookmark = (journalId: string) => {
112→    bookmarkMutation.mutate(journalId);
113→  };
114→
115→  const handleRepost = (journalId: string) => {
116→    Alert.alert('Repost', 'Repost this to your feed?', [
117→      {text: 'Cancel', style: 'cancel'},
118→      {text: 'Repost', onPress: () => repostMutation.mutate(journalId)},
119→    ]);
120→  };
121→
122→  const posts = useMemo(
123→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
124→    [query.data?.pages],
125→  );
126→
127→  return (
128→    <>
129→    <FlatList
130→      data={posts}
131→      keyExtractor={item => item.id}
132→      showsVerticalScrollIndicator={false}
133→      contentContainerStyle={styles.list}
134→      ListHeaderComponent={headerComponent}
135→      onEndReachedThreshold={0.3}
136→      onEndReached={() => {
137→        if (query.hasNextPage && !query.isFetchingNextPage) {
138→          query.fetchNextPage();
139→        }
140→      }}
141→      ListEmptyComponent={
142→        query.isLoading ? (
143→          <View style={styles.skeletons}>
144→            <PostCardSkeleton />
145→            <PostCardSkeleton />
146→            <PostCardSkeleton />
147→          </View>
148→        ) : (
149→          <EmptyState
150→            title="No writings yet"
151→            subtitle="Journal posts will appear here."
152→          />
153→        )
154→      }
155→      ListFooterComponent={
156→        query.isFetchingNextPage ? (
157→          <View style={styles.footer}>
158→            <PostCardSkeleton />
159→          </View>
160→        ) : null
161→      }
162→      renderItem={({item}) => {
163→        const preview = extractPlainText(item.content).slice(0, 180);
164→        const likeCount = resolveCount(item.like_count, item.likes_count);
165→        const commentCount = resolveCount(item.comment_count, item.comments_count);
166→        const bookmarkCount = resolveCount(item.bookmark_count);
167→        const bannerImage = extractBannerImage(item.content, (item as any).images);
168→
169→        const handleAuthorPress = () => {
170→          const authorId = item.users?.id ?? item.user_id;
171→          if (!authorId) return;
172→          if (authorId === user?.id) {
173→            navigation.navigate('Main' as any, {screen: 'Profile'});
174→          } else {
175→            navigation.navigate('VisitProfile', {
176→              userId: authorId,
177→              username: item.users?.username ?? undefined,
178→            });
179→          }
180→        };
181→
182→        const receiverId = item.user_id ?? item.users?.id ?? '';
183→
184→        return (
185→          <PostCard
186→            title={item.title || 'Untitled Post'}
187→            bodyPreview={preview || 'No preview text available.'}
188→            authorName={item.users?.name || 'Unknown author'}
189→            authorAvatar={item.users?.image_url}
190→            authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
191→            bannerImage={bannerImage}
192→            postType={item.post_type ?? undefined}
193→            likeCount={likeCount}
194→            commentCount={commentCount}
195→            bookmarkCount={bookmarkCount}
196→            isBookmarked={!!item.has_bookmarked}
197→            userReaction={item.user_reaction}
198→            onReact={type => handleReact(item.id, receiverId, type)}
199→            onComment={() => handleComment(item.id, receiverId, commentCount)}
200→            onBookmark={() => handleBookmark(item.id)}
201→            onRepost={() => handleRepost(item.id)}
202→            onPress={() =>
203→              navigation.navigate('PostDetail', {journalId: item.id})
204→            }
205→            onAuthorPress={handleAuthorPress}
206→          />
207→        );
208→      }}
209→      ItemSeparatorComponent={() => <View style={styles.separator} />}
210→    />
211→    {commentModal && (
212→      <CommentModal
213→        visible
214→        postId={commentModal.postId}
215→        receiverId={commentModal.receiverId}
