 1→import {Alert} from 'react-native';
 2→import {useMutation, type QueryKey} from '@tanstack/react-query';
 3→import {socialApi} from '../lib/api/socialApi';
 4→import {queryClient} from '../lib/queryClient';
 5→import type {CursorPage, JournalItem} from '../lib/api/mobileApi';
 6→
 7→type InfiniteData = {pages: CursorPage<JournalItem>[]};
 8→
 9→export function useBookmarkMutation(token: string, queryKey: QueryKey) {
10→  return useMutation({
11→    mutationFn: async (journalId: string) => {
12→      if (!token) throw new Error('Please log in to bookmark.');
13→      return socialApi.toggleBookmark(token, {journalId});
14→    },
15→    onMutate: async (journalId: string) => {
16→      await queryClient.cancelQueries({queryKey});
17→      const prev = queryClient.getQueryData<InfiniteData>(queryKey);
18→      if (prev) {
19→        queryClient.setQueryData<InfiniteData>(queryKey, old => {
20→          if (!old) return old;
21→          return {
22→            ...old,
23→            pages: old.pages.map(page => ({
24→              ...page,
25→              data: page.data.map(item => {
26→                if (item.id !== journalId) return item;
27→                const wasBookmarked = !!item.has_bookmarked;
28→                const currentCount = (item.bookmark_count?.[0]?.count ?? 0) as number;
29→                const delta = wasBookmarked ? -1 : 1;
30→                return {
31→                  ...item,
32→                  has_bookmarked: !wasBookmarked,
33→                  bookmark_count: [{count: Math.max(0, currentCount + delta)}],
34→                };
35→              }),
36→            })),
37→          };
38→        });
39→      }
40→      return {prev};
41→    },
42→    onError: (_err: unknown, _journalId: string, context: {prev?: InfiniteData} | undefined) => {
43→      if (context?.prev) {
44→        queryClient.setQueryData(queryKey, context.prev);
45→      }
46→      Alert.alert('Error', 'Could not update bookmark. Please try again.');
47→    },
48→    onSettled: () => {
49→      queryClient.invalidateQueries({queryKey});
50→    },
51→  });
52→}
53→
54→export function useRepostMutation(token: string) {
55→  return useMutation({
56→    mutationFn: async (sourceJournalId: string) => {
57→      if (!token) throw new Error('Please log in to repost.');
58→      return socialApi.createRepost(token, {sourceJournalId});
59→    },
60→    onSuccess: () => {
61→      Alert.alert('Reposted', 'This post has been shared to your feed.');
62→      queryClient.invalidateQueries({queryKey: ['feed']});
63→    },
64→    onError: () => {
65→      Alert.alert('Error', 'Could not repost. Please try again.');
66→    },
67→  });
68→}
