468→export const useReactionMutation = (session, userId) => {
469→    const queryClient = useQueryClient();
470→    const inFlightRef = useRef(new Set());
471→
472→    const mutation = useMutation({
473→        mutationFn: (data) => toggleReaction(session?.access_token, data),
474→
475→        onMutate: async (data) => {
476→            queryClient.cancelQueries({ queryKey: ['journals'] });
477→            queryClient.cancelQueries({ queryKey: ['userJournals'] });
478→            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });
479→
480→            const previousData = [
481→                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
482→                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
483→                ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
484→            ];
485→
486→            const updater = (journal) => {
487→                if (journal.id !== data.journalId) return journal;
488→
489→                const currentReaction = journal?.user_reaction;
490→                const currentCount = normalizeCount(journal?.reaction_count?.[0]?.count);
491→
492→                let nextReaction;
493→                let nextCount;
494→
495→                if (currentReaction === data.reactionType) {
496→                    // Toggle off
497→                    nextReaction = null;
498→                    nextCount = Math.max(currentCount - 1, 0);
499→                } else if (currentReaction) {
500→                    // Switch reaction (count stays same)
501→                    nextReaction = data.reactionType;
502→                    nextCount = currentCount;
503→                } else {
504→                    // New reaction
505→                    nextReaction = data.reactionType;
506→                    nextCount = currentCount + 1;
507→                }
508→
509→                return {
510→                    ...journal,
511→                    user_reaction: nextReaction,
512→                    reaction_count: [{ count: nextCount }],
513→                };
514→            };
515→
516→            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
517→            queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
518→            queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => updateInfiniteJournalsCache(old, updater));
519→
520→            return { previousData };
521→        },
522→
523→        onError: (err, data, context) => {
524→            context?.previousData?.forEach(([key, value]) => {
525→                queryClient.setQueryData(key, value);
526→            });
527→        },
528→
529→        onSettled: () => {
530→            queryClient.invalidateQueries({ queryKey: ['journals'] });
531→            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
532→            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
533→            queryClient.invalidateQueries({ queryKey: ['postReactions'] });
534→        },
535→    });
536→
537→    const guardedMutate = (variables, options) => {
538→        const journalKey = toJournalKey(variables?.journalId);
539→        if (journalKey && inFlightRef.current.has(journalKey)) return;
540→
541→        if (journalKey) inFlightRef.current.add(journalKey);
542→
543→        mutation.mutate(variables, {
544→            ...options,
545→            onSettled: (data, error, vars, context) => {
546→                if (journalKey) inFlightRef.current.delete(journalKey);
547→                options?.onSettled?.(data, error, vars, context);
548→            },
549→        });
550→    };
551→
552→    return { ...mutation, mutate: guardedMutate };
553→}
